export default async function DetailPost({
    params
}: 
    {
        params: {id: string}
    }
){

    const { id } = await params;

    const response = await fetch(`https://dummyjson.com/posts/${id}`)
    const data = await response.json()
    


    
    return (
        <div>
        <h1>{data.title}</h1>
        <h1>{data.body}</h1>
        </div>
    );
}